# DiskStation Monitor — Fix auth page button responsiveness
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\AUTHFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Fixing auth page..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\dsm-auth.html"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/dsm-auth.html" -ForegroundColor Green

git add frontend/dsm-auth.html
git commit -m "fix: auth page buttons — use addEventListener instead of module-scoped onclick"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Pushed! Netlify rebuilding — buttons will work after deploy." -ForegroundColor Green
    Write-Host "   https://dsm.4thandbailey.com/dsm-auth.html" -ForegroundColor Cyan
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}